interface SidebarNavProps {
  className?: string;
  user?: {
    name: string;
    avatar?: string;
  };
}

export function SidebarNav({ className, user }: SidebarNavProps) {
  const pathname = usePathname();

  return (
    <TooltipProvider delayDuration={0}>
      <aside
        className={cn(
          'fixed left-0 top-0 z-40 h-screen w-[85px] flex-col',
          'bg-[#4A4A4A]',
          'hidden lg:flex',
          className
        )}
      >
        {/* Logo - Top */}
        <div className="flex h-[85px] items-center justify-center">
          <div className="w-[53px] h-[53px] relative">
            <Image
              src="/icons/Logo.svg"
              alt="Highland City Club"
              width={53}
              height={53}
              className="object-contain"
            />
          </div>
        </div>

        {/* Main Navigation */}
        <nav className="flex-1 flex flex-col items-center py-2">
          {mainNavItems.map((item) => {
            const isActive = pathname === item.href || pathname.startsWith(item.href + '/');
            const Icon = item.Icon;

            return (
              <Tooltip key={item.href}>
                <TooltipTrigger asChild>
                  <Link
                    href={item.href}
                    className={cn(
                      'flex flex-col items-center justify-center gap-1.5 w-[70px] h-[70px] rounded-lg transition-all',
                      isActive
                        ? 'border-[1.5px] border-dashed border-white/50'
                        : 'border-[1.5px] border-transparent'
                    )}
                  >
                    <Icon className={cn(
                      'w-6 h-6',
                      isActive ? 'text-white' : 'text-[#B4B4B4]'
                    )} />
                    <span className={cn(
                      'text-[11px] font-bold',
                      isActive ? 'text-white' : 'text-[#B4B4B4]'
                    )}>{item.label}</span>
                  </Link>
                </TooltipTrigger>
                <TooltipContent side="right" sideOffset={8}>
                  {item.label}
                </TooltipContent>
              </Tooltip>
            );
          })}
        </nav>

        {/* Bottom Section - Admin + User */}
        <div className="flex flex-col items-center gap-3 py-4">
          {/* Admin/Settings */}
          <Tooltip>
            <TooltipTrigger asChild>
              <Link
                href="/admin/users"
                className={cn(
                  'flex flex-col items-center justify-center gap-1.5 w-[70px] h-[70px] rounded-lg transition-all',
                  pathname.startsWith('/admin')
                    ? 'border-[1.5px] border-dashed border-white/50'
                    : 'border-[1.5px] border-transparent hover:border-white/20'
                )}
              >
                <AdminIcon className={cn(
                  'w-6 h-6',
                  pathname.startsWith('/admin') ? 'text-white' : 'text-[#B4B4B4]'
                )} />
                <span className={cn(
                  'text-[11px] font-bold',
                  pathname.startsWith('/admin') ? 'text-white' : 'text-[#B4B4B4]'
                )}>Admin</span>
              </Link>
            </TooltipTrigger>
            <TooltipContent side="right" sideOffset={8}>
              Admin Settings
            </TooltipContent>
          </Tooltip>

          {/* User Avatar */}
          {user && (
            <Tooltip>
              <TooltipTrigger asChild>
                <button className="flex flex-col items-center justify-center gap-1.5 w-[65px] py-2">
                  <Avatar className="h-10 w-10 border-2 border-primary">
                    {user.avatar ? (
                      <AvatarImage src={user.avatar} alt={user.name} />
                    ) : null}
                    <AvatarFallback className="bg-primary text-primary-foreground text-sm">
                      {user.name.split(' ').map(n => n[0]).join('').slice(0, 2)}
                    </AvatarFallback>
                  </Avatar>
                  <span className="text-[10px] text-white/70 truncate max-w-14">
                    {user.name.split(' ')[0]}
                  </span>
                </button>
              </TooltipTrigger>
              <TooltipContent side="right" sideOffset={8}>
                {user.name}
              </TooltipContent>
            </Tooltip>
          )}
        </div>
      </aside>
    </TooltipProvider>
  );
}
